/**
 * Provides the MagicBell context to all components in the SDK.
 *
 * Wrap your app in this component to enable access to the MagicBell API client,
 * local-first user/session state, and shared configuration. Required for components
 * like `Inbox`, `FloatingInbox`, and `SlackButton` to function.
 */
type Props = {
    /**
     * The MagicBell User JWT
     */
    token: string;
    /**
     * Override the base API URL (used for testing/staging).
     * @internal
     */
    baseUrl?: string;
    /**
     * Override the socket server URL (used for testing/staging).
     * @internal
     */
    socketUrl?: string;
    /**
     * Enable or disable toast notifications.
     * @default true
     */
    toasts?: boolean;
    /**
     * Elements to render inside the provider.
     * @type {Element}
     */
    children?: any;
};
declare function ContextProvider(props: Props): import("react/jsx-runtime").JSX.Element;
export default ContextProvider;

